@startuml

package "common" {
  package "domain" {
    package "repository" {
      interface "FeatureConfigRepository" {
        + Future<FeatureConfig> fetch()
      }
    }

    package "entities" {
      class "FeatureConfig" {
        o isPasswordSignInOptionEnabled : bool
        o isDebugMenuEnabled : bool
      }
    }

    package "usecases" {
      class "FetchFeatureConfigUseCase" {
        + Future<FeatureConfig> call(FeatureConfigParam params)
      }
    }

    package "parameters" {
      class "FeatureConfigParam" {
        o isPasswordSignInOptionEnabled : bool
        o isDebugMenuEnabled : bool
      }
    }
  }
}

package "base" {
  package "domain " {
    package "usecases " {
      interface "UseCase" <<Type, Params>> {
        call: Type
      }
    }
  }
}

FeatureConfig ..> FeatureConfigRepository : uses
FetchFeatureConfigUseCase ..> FeatureConfigRepository : uses
FetchFeatureConfigUseCase --> FeatureConfigParam : uses
FetchFeatureConfigUseCase ..[#black]..> UseCase : uses

@enduml
